export const useLikeMutation = (session, userId) =>{
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: (data) => clickLike(session?.access_token, data),

        onMutate: async(data) => {
            queryClient.cancelQueries({ queryKey: ['journals'] });  // Line 62 - cancels fetches
            const previousData = queryClient.getQueriesData({ queryKey: ['journals'] });

            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => {
                return updateInfiniteJournalsCache(old, (journal) => {
                    if(journal.id !== data.journalId) return journal;
                    const isLiked = journal.has_liked;
                    const count = journal.like_count?.[0]?.count ?? 0;
                    return{
                        ...journal,
                        has_liked: !isLiked,
                        like_count: [{count: isLiked ? count - 1 : count + 1}]
                    };
                });
            });
            return {previousData};
        },
        onError: (err, data, context) => {
            context?.previousData?.forEach(([key, value]) => {
                queryClient.setQueryData(key, value);
            });
        },
        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: ['journals'] });  // Line 89
        },
    })
}
```

**Query Key:** `['journals']` (with optional userId param in PostCards: `['journals', userId]`)

